SELECT mr.*, dv.generic_name as drug_name
FROM medication_records mr
LEFT JOIN drugs_vaccines dv ON mr.drug_id = dv.id


        (mr.ear_tag LIKE CONCAT('%', #{search}, '%')
        OR dv.generic_name LIKE CONCAT('%', #{search}, '%')
        OR mr.reason LIKE CONCAT('%', #{search}, '%'))


        AND dv.generic_name = #{drug}


        AND mr.event_time >= #{dateFrom}


        AND mr.event_time <= #{dateTo}


ORDER BY mr.event_time DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM medication_records mr
LEFT JOIN drugs_vaccines dv ON mr.drug_id = dv.id


        (mr.ear_tag LIKE CONCAT('%', #{search}, '%')
        OR dv.generic_name LIKE CONCAT('%', #{search}, '%')
        OR mr.reason LIKE CONCAT('%', #{search}, '%'))


        AND dv.generic_name = #{drug}


